# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import sqlite3
from collections import Counter
import os
import numpy as np
import joblib
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.metrics import accuracy_score
from fastapi import FastAPI, HTTPException, BackgroundTasks
from pydantic import BaseModel
from typing import List, Optional

# --- Configuration ---
DATABASE_FILE = "labeling_system.db"
MODEL_DIR = "trained_models"
MODEL_FILE = os.path.join(MODEL_DIR, "image_classifier.joblib")
MIN_VOTES_FOR_AGGREGATION = 3 # Minimum number of labels for an image to be considered for aggregation
MAJORITY_PERCENTAGE_THRESHOLD = 0.6 # A label needs at least 60% of votes to be considered a majority

# --- Pydantic Models ---
class ImageBase(BaseModel):
    image_url: str

class ImageCreate(ImageBase):
    pass

class ImageResponse(ImageBase):
    image_id: int
    status: str

    class Config:
        orm_mode = True

class LabelCreate(BaseModel):
    image_id: int
    annotator_id: str
    label_value: str

class AggregatedLabelResponse(BaseModel):
    image_id: int
    majority_label: str
    num_votes: int
    is_finalized: bool

    class Config:
        orm_mode = True

class TrainingStatusResponse(BaseModel):
    message: str
    model_path: Optional[str] = None
    accuracy: Optional[float] = None
    num_samples: Optional[int] = None

class PredictionResponse(BaseModel):
    image_url: str
    predicted_label: Optional[str] = None
    message: str

# --- Database Operations ---
def get_db_connection():
    conn = sqlite3.connect(DATABASE_FILE)
    conn.row_factory = sqlite3.Row # Allows accessing columns by name
    return conn

def init_db():
    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS images (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            image_url TEXT NOT NULL UNIQUE,
            status TEXT DEFAULT 'pending'
        );
    """)

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS labels (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            image_id INTEGER NOT NULL,
            annotator_id TEXT NOT NULL,
            label_value TEXT NOT NULL,
            timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (image_id) REFERENCES images(id)
        );
    """)

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS aggregated_labels (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            image_id INTEGER NOT NULL UNIQUE,
            majority_label TEXT,
            num_votes INTEGER,
            is_finalized BOOLEAN DEFAULT FALSE,
            timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (image_id) REFERENCES images(id)
        );
    """)
    conn.commit()
    conn.close()

def add_image_db(image_url: str):
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("INSERT INTO images (image_url) VALUES (?)", (image_url,))
        conn.commit()
        image_id = cursor.lastrowid
        return {"image_id": image_id, "image_url": image_url, "status": "pending"}
    except sqlite3.IntegrityError:
        cursor.execute("SELECT id, image_url, status FROM images WHERE image_url = ?", (image_url,))
        existing_image = cursor.fetchone()
        return {"image_id": existing_image["id"], "image_url": existing_image["image_url"], "status": existing_image["status"]}
    finally:
        conn.close()

def get_image_db(image_id: int):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT id, image_url, status FROM images WHERE id = ?", (image_id,))
    image = cursor.fetchone()
    conn.close()
    return image

def submit_label_db(image_id: int, annotator_id: str, label_value: str):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute(
        "SELECT id FROM labels WHERE image_id = ? AND annotator_id = ?",
        (image_id, annotator_id)
    )
    if cursor.fetchone():
        conn.close()
        return False, "Annotator already labeled this image."

    cursor.execute(
        "INSERT INTO labels (image_id, annotator_id, label_value) VALUES (?, ?, ?)",
        (image_id, annotator_id, label_value)
    )
    conn.commit()
    conn.close()
    return True, "Label submitted successfully."

def get_labels_for_image_db(image_id: int):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT label_value FROM labels WHERE image_id = ?", (image_id,))
    labels = [row["label_value"] for row in cursor.fetchall()]
    conn.close()
    return labels

def _update_aggregated_label_db(conn, image_id: int, majority_label: str, num_votes: int, is_finalized: bool):
    cursor = conn.cursor()
    cursor.execute(
        """
        INSERT OR REPLACE INTO aggregated_labels (image_id, majority_label, num_votes, is_finalized)
        VALUES (?, ?, ?, ?)
        """,
        (image_id, majority_label, num_votes, is_finalized)
    )
    if is_finalized:
        cursor.execute(
            "UPDATE images SET status = 'labeled' WHERE id = ?",
            (image_id,)
        )
    conn.commit()

def aggregate_labels_for_image_db(image_id: int):
    conn = get_db_connection()
    labels = get_labels_for_image_db(image_id)
    if not labels:
        conn.close()
        return None

    label_counts = Counter(labels)
    if not label_counts:
        conn.close()
        return None

    majority_label = label_counts.most_common(1)[0][0]
    num_majority_votes = label_counts.most_common(1)[0][1]
    total_votes = sum(label_counts.values())

    is_finalized = (total_votes >= MIN_VOTES_FOR_AGGREGATION and
                   (num_majority_votes / total_votes) >= MAJORITY_PERCENTAGE_THRESHOLD)

    _update_aggregated_label_db(conn, image_id, majority_label, num_majority_votes, is_finalized)
    conn.close()
    return {"image_id": image_id, "majority_label": majority_label, "num_votes": num_majority_votes, "is_finalized": is_finalized}

def get_all_aggregated_labels_db(only_finalized: bool = True):
    conn = get_db_connection()
    cursor = conn.cursor()
    query = "SELECT image_id, majority_label, num_votes, is_finalized FROM aggregated_labels"
    if only_finalized:
        query += " WHERE is_finalized = TRUE"
    cursor.execute(query)
    aggregated_labels = cursor.fetchall()
    conn.close()
    return aggregated_labels

def get_aggregated_label_for_image_db(image_id: int):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute(
        "SELECT image_id, majority_label, num_votes, is_finalized FROM aggregated_labels WHERE image_id = ?",
        (image_id,)
    )
    result = cursor.fetchone()
    conn.close()
    return result

# --- Model Training and Prediction ---
def load_and_preprocess_image(image_url: str):
    # This is a placeholder for actual image loading and feature extraction.
    # In a real system:
    # 1. Download/access image from image_url (e.g., using requests library)
    # 2. Use a library like PIL (Pillow) or OpenCV to open and preprocess the image (resize, convert to grayscale, etc.)
    # 3. Extract features. This could be flattening pixel values, or using a pre-trained deep learning model's embeddings.
    # For demonstration, we'll return a deterministic random feature vector based on the URL.
    np.random.seed(hash(image_url) % (2**32 - 1)) # Ensures consistent features for the same URL
    return np.random.rand(1024) # Example: a 1024-dimensional feature vector

def train_model():
    os.makedirs(MODEL_DIR, exist_ok=True)

    aggregated_data = get_all_aggregated_labels_db(only_finalized=True)

    if not aggregated_data:
        return {"message": "No finalized aggregated labels available for training.", "model_path": None}

    X = [] # Features (simulated image data)
    y = [] # Labels

    label_to_int = {}
    next_int_label = 0

    for item in aggregated_data:
        image_id = item["image_id"]
        majority_label = item["majority_label"]
        image = get_image_db(image_id)
        if image:
            features = load_and_preprocess_image(image["image_url"])
            X.append(features)

            if majority_label not in label_to_int:
                label_to_int[majority_label] = next_int_label
                next_int_label += 1
            y.append(label_to_int[majority_label])

    if not X:
        return {"message": "No image data could be loaded for training.", "model_path": None}

    X = np.array(X)
    y = np.array(y)

    model = Pipeline([
        ('scaler', StandardScaler()),
        ('classifier', LogisticRegression(max_iter=1000, solver='liblinear'))
    ])

    print(f"Training model with {len(X)} samples and {len(label_to_int)} classes...")
    model.fit(X, y)

    joblib.dump(model, MODEL_FILE)
    joblib.dump(label_to_int, os.path.join(MODEL_DIR, "label_to_int.joblib"))

    print(f"Model trained and saved to {MODEL_FILE}")

    y_pred = model.predict(X)
    accuracy = accuracy_score(y, y_pred)
    print(f"Training Accuracy: {accuracy:.4f}")

    return {"message": "Model training completed successfully.", "model_path": MODEL_FILE, "accuracy": accuracy, "num_samples": len(X)}

def load_model():
    if os.path.exists(MODEL_FILE):
        return joblib.load(MODEL_FILE)
    return None

def predict_label(image_url: str):
    model = load_model()
    if not model:
        return None, "No trained model available."

    label_map_file = os.path.join(MODEL_DIR, "label_to_int.joblib")
    if not os.path.exists(label_map_file):
        return None, "Label mapping not found. Model might be corrupted or training incomplete."

    label_to_int = joblib.load(label_map_file)
    int_to_label = {v: k for k, v in label_to_int.items()}

    features = load_and_preprocess_image(image_url).reshape(1, -1)
    prediction_int = model.predict(features)[0]
    predicted_label = int_to_label.get(prediction_int)

    return predicted_label, "Prediction successful."

# --- FastAPI Application ---
app = FastAPI(
    title="Crowdsourced Data Labeling System",
    description="API for image labeling, aggregation, and model training for data annotation platforms."
)

@app.on_event("startup")
async def startup_event():
    init_db()

@app.post("/images", response_model=ImageResponse, summary="Register a new image for labeling")
async def register_image(image: ImageCreate):
    image_data = add_image_db(image.image_url)
    if image_data:
        return ImageResponse(**image_data)
    raise HTTPException(status_code=500, detail="Could not register image.")

@app.get("/images/{image_id}", response_model=ImageResponse, summary="Get details for a specific image")
async def get_image_details(image_id: int):
    image_data = get_image_db(image_id)
    if image_data:
        return ImageResponse(image_id=image_data["id"], image_url=image_data["image_url"], status=image_data["status"])
    raise HTTPException(status_code=404, detail="Image not found.")

@app.post("/labels", summary="Submit a label for an image")
async def submit_image_label(label: LabelCreate):
    success, message = submit_label_db(label.image_id, label.annotator_id, label.label_value)
    if not success:
        raise HTTPException(status_code=400, detail=message)

    aggregated_data = aggregate_labels_for_image_db(label.image_id)
    if aggregated_data:
        status_message = f"Label submitted. Aggregation for image {label.image_id} performed. Current majority: {aggregated_data['majority_label']} ({aggregated_data['num_votes']} votes). Finalized: {aggregated_data['is_finalized']}."
    else:
        status_message = f"Label submitted. No sufficient labels yet for aggregation for image {label.image_id}."

    return {"message": status_message}

@app.get("/labels/{image_id}/raw", summary="Get all raw labels for an image")
async def get_raw_labels_for_image(image_id: int):
    labels = get_labels_for_image_db(image_id)
    if labels is None:
        raise HTTPException(status_code=404, detail="Image not found or no labels yet.")
    return {"image_id": image_id, "raw_labels": labels}

@app.get("/labels/{image_id}/aggregated", response_model=AggregatedLabelResponse, summary="Get aggregated label for a specific image")
async def get_aggregated_label(image_id: int):
    aggregated_data = get_aggregated_label_for_image_db(image_id)
    if aggregated_data:
        return AggregatedLabelResponse(
            image_id=aggregated_data["image_id"],
            majority_label=aggregated_data["majority_label"],
            num_votes=aggregated_data["num_votes"],
            is_finalized=aggregated_data["is_finalized"]
        )
    raise HTTPException(status_code=404, detail="Aggregated label not found for this image.")

@app.get("/aggregated_labels", response_model=List[AggregatedLabelResponse], summary="Get all finalized aggregated labels")
async def get_all_finalized_aggregated_labels():
    aggregated_labels = get_all_aggregated_labels_db(only_finalized=True)
    return [AggregatedLabelResponse(
        image_id=item["image_id"],
        majority_label=item["majority_label"],
        num_votes=item["num_votes"],
        is_finalized=item["is_finalized"]
    ) for item in aggregated_labels]

@app.post("/train", response_model=TrainingStatusResponse, summary="Trigger model training on finalized labeled data")
async def trigger_model_training(background_tasks: BackgroundTasks):
    background_tasks.add_task(train_model)
    return TrainingStatusResponse(message="Model training started in the background. Check server logs for progress.")

@app.post("/predict", response_model=PredictionResponse, summary="Make a prediction using the trained model")
async def predict(image: ImageCreate):
    predicted_label, message = predict_label(image.image_url)
    if predicted_label:
        return PredictionResponse(image_url=image.image_url, predicted_label=predicted_label, message=message)
    raise HTTPException(status_code=500, detail=message)

